from nltk.logic.syntax import *
from nltk.logic.propositional import *

def convert_to_nltk_proposition(expr):
    if expr.is_Atom():
        return Symbol(expr.name)
    elif expr.is_Variable():
        return Variable(expr.name)
    elif expr.is_Connective():
        c = Connective(expr.name)
        for a in expr.arguments:
            c.append(convert_to_nltk_proposition(a))
        return c
    elif expr.is_Expression():
        e = Expression(expr.name)
        for a in expr.arguments:
            e.append(convert_to_nltk_proposition(a))
        return e
    else:
        raise Exception("Invalid expression")

def evaluate_nltk_proposition(p):
    if p.is_Atom():
        return True if p.name == "True" else False if p.name == "False" else None
    elif p.is_Variable():
        return None
    elif p.is_Connective():
        return {Connective.AND: all,
                Connective.OR: any,
                Connective.NOT: not,
                Connective.IMPLIES: lambda x, y: y if x else True,
                Connective.EQUALS: lambda x, y: True if x == y else False,
                Connective.NEQ: lambda x, y: True if x!= y else False}[p.name](*[evaluate_nltk_proposition(x) for x in p.arguments])
    elif p.is_Expression():
        return {Expression.ATOM: lambda x, y: True if x == y else False,
                Expression.AND: lambda x, y: True if x and y else False,
                Expression.OR: lambda x, y: True if x or y else False}[p.name](*[evaluate_nltk_proposition(x) for x in p.arguments])
    else:
        raise Exception("Invalid expression")

def evaluate(expr):
    return evaluate_nltk_proposition(convert_to_nltk_proposition(expr))


def solve():
    variables = {x.name for x in Proposition.variables(PROPOSITION)}
    answer = None
    for premise in PREMISES:
        for var in variables:
            if var not in premise:
                premise = premise.replace("True", "True if {} is True else False".format(var))
                premise = premise.replace("False", "False if {} is True else True".format(var))
        if eval(premise):
            answer = premise
            break
    if answer is None:
        return "Uncertain"
    else:
        return "True" if eval(answer) else "False"


def main():
    PROPOSITION = read_proposition(PROPOSITION_TEXT)
    PREMISES = [read_proposition(p) for p in PREMISES_TEXT]
    print(solve())


if __name__ == "__main__":
    main()
